const item = $input.first().json;
const lang = String(item.lang || '').trim().toLowerCase();

if (!lang) {
  throw new Error('Configure Job: lang is required. Set to "en" or "hi".');
}
if (!['en', 'hi'].includes(lang)) {
  throw new Error(`Configure Job: invalid lang "${lang}" — use "en" or "hi".`);
}

let theme = String(item.theme ?? '').trim().toLowerCase();
if (theme === 'auto') {
  theme = '';
}

const themesCsv = String(item.themesCsv ?? '').trim();
if (themesCsv) {
  const pool = themesCsv.split(',').map((t) => t.trim().toLowerCase()).filter(Boolean);
  if (pool.length === 0) {
    throw new Error('Configure Job: themesCsv is set but contains no valid themes.');
  }
}

const duration = Number(item.duration ?? 45);
if (Number.isNaN(duration) || duration < 10 || duration > 120) {
  throw new Error('Configure Job: duration must be between 10 and 120 seconds.');
}

const tier = String(item.tier || 'flux').trim().toLowerCase();
if (!['flux', 'wan'].includes(tier)) {
  throw new Error(`Configure Job: invalid tier "${tier}" — use "flux" or "wan".`);
}

const privacy = String(item.youtubePrivacy || 'private').trim().toLowerCase();
if (!['private', 'unlisted', 'public'].includes(privacy)) {
  throw new Error(`Configure Job: invalid youtubePrivacy "${privacy}".`);
}

const pipelineApiBase = String(item.pipelineApiBase || item.pipelineApiUrl || 'http://127.0.0.1:8765')
  .trim()
  .replace(/\/generate\/?$/, '')
  .replace(/\/$/, '');
const pipelineHostPath = String(item.pipelineHostPath || '/Users/user/Downloads/n8n-youtube').trim().replace(/\/$/, '');
const pipelineContainerPath = String(item.pipelineContainerPath || '/home/node/.n8n-files/youtube_videos').trim().replace(/\/$/, '');

return [{
  json: {
    lang,
    theme,
    themesCsv,
    themeRandom: !theme,
    duration,
    tier,
    youtubePrivacy: privacy,
    pipelineApiBase,
    pipelineHostPath,
    pipelineContainerPath,
  },
}];

const item = $input.first().json;
const result = item.final_video ? item : (item.body || item);

if (result.error) {
  throw new Error(result.error);
}
if (!result.final_video && !result.video_url) {
  throw new Error('Pipeline response missing final_video: ' + JSON.stringify(result).slice(0, 2000));
}

function loadConfig() {
  for (const name of ['Validate Language', 'Configure Job']) {
    try {
      const row = $(name).first();
      if (row && row.json) return row.json;
    } catch (_) { /* node not in this execution */ }
  }
  return {};
}

function stripTrailingSlash(s) {
  return s.endsWith('/') ? s.slice(0, -1) : s;
}

const config = loadConfig();
const hostRoot = stripTrailingSlash(String(config.pipelineHostPath || '/Users/user/Downloads/n8n-youtube'));
const outputHostRoot = hostRoot + '/output';
const containerRoot = stripTrailingSlash(String(config.pipelineContainerPath || '/home/node/.n8n-files/youtube_videos'));

function toContainerPath(p) {
  const path = String(p || '');
  if (path.startsWith(containerRoot + '/') || path === containerRoot) return path;
  if (path.startsWith(outputHostRoot + '/')) return containerRoot + path.slice(outputHostRoot.length);
  if (path.startsWith(hostRoot + '/output/')) return containerRoot + path.slice((hostRoot + '/output').length);
  if (path.startsWith(hostRoot + '/')) return '/pipeline' + path.slice(hostRoot.length);
  return path;
}

const NL = String.fromCharCode(10);
const script = result.script || {};
const lang = script.language || config.lang || 'en';
const theme = script.content_type || script.theme || result.theme || config.theme || 'story';
const isHindi = lang === 'hi' || lang === 'hindi';
const langTag = isHindi ? 'hindi' : 'english';

// Hashtags: prefer LLM hashtags, else derive. Strip '#', dedupe, always include shorts.
let hashtags = Array.isArray(script.hashtags) && script.hashtags.length
  ? script.hashtags.slice()
  : ['shorts', theme, langTag, 'kids', 'story'];
hashtags = hashtags
  .map((h) => String(h).replace(/[\u0900-\u097F]+/g, '').split('#').join('').trim().split(' ').filter(Boolean).join(''))
  .filter(Boolean)
  .map((h) => h.toLowerCase());
if (!hashtags.includes('shorts')) hashtags.push('shorts');
hashtags = Array.from(new Set(hashtags)).slice(0, 6);
const hashtagLine = hashtags.slice(0, 5).map((h) => '#' + h).join(' ');

function buildUploadTitle(base, allTags, maxChars, hashtagCount) {
  let titleBase = String(base || '').trim();
  if (titleBase.includes('#')) return titleBase.slice(0, maxChars);
  const titleTags = allTags.slice(0, hashtagCount);
  if (!titleTags.length) return titleBase.slice(0, maxChars);
  const suffix = ' ' + titleTags.map((h) => '#' + h).join(' ');
  const maxBase = maxChars - suffix.length;
  if (maxBase <= 10) return titleBase.slice(0, maxChars);
  if (titleBase.length > maxBase) titleBase = titleBase.slice(0, maxBase - 1).trim() + '…';
  return (titleBase + suffix).slice(0, maxChars);
}

// Title: LLM SEO title (often already includes hashtags) or base title + first LLM hashtags.
const titleHashtagCount = 2;
const titleMaxChars = 100;
let title = buildUploadTitle(
  script.youtube_title || script.title || ('Kids ' + theme + ' - ' + langTag),
  hashtags,
  titleMaxChars,
  titleHashtagCount,
);
if (title.length > titleMaxChars) title = title.slice(0, titleMaxChars - 1).trim() + '…';

// Description: prefer LLM SEO description, else narration. Append hashtags. Cap ~4900 chars.
const narration = script.narration || script.script || '';
const descBody = String(script.youtube_description || narration || '').trim();
let description = (descBody + NL + NL + hashtagLine).trim();
if (description.length > 4900) description = description.slice(0, 4900);

// Tags: prefer LLM SEO tags, else derive. Sanitize, dedupe, obey YouTube ~500-char total budget.
let tagList = Array.isArray(script.youtube_tags) && script.youtube_tags.length
  ? script.youtube_tags.slice()
  : [theme, 'kids', 'story', 'shorts', 'hindi', 'cartoon'];
tagList = tagList
  .map((t) => String(t).replace(/[\u0900-\u097F]+/g, '').split('#').join('').split(',').join('').trim().split(' ').filter(Boolean).join(' '))
  .filter(Boolean)
  .map((t) => t.toLowerCase());
tagList = Array.from(new Set(tagList));
const cappedTags = [];
let tagChars = 0;
for (const t of tagList) {
  const add = (cappedTags.length ? 1 : 0) + t.length;
  if (tagChars + add > 480) break;
  cappedTags.push(t);
  tagChars += add;
  if (cappedTags.length >= 15) break;
}
const tags = cappedTags.join(',');

const apiBase = config.pipelineApiBase || 'http://host.docker.internal:8765';
const videoUrl = result.video_url || (stripTrailingSlash(apiBase) + '/video/' + result.run_id);

return [{
  json: {
    final_video: toContainerPath(result.final_video),
    video_url: videoUrl,
    output_dir: toContainerPath(result.output_dir),
    run_id: result.run_id,
    title,
    description,
    tags,
    hashtags: hashtagLine,
    hookText: String(script.hook_text || ''),
    titleVariants: Array.isArray(script.title_variants) ? script.title_variants : [],
    youtubePrivacy: config.youtubePrivacy || 'public',
    selfDeclaredMadeForKids: false,
    lang,
    theme,
  },
}];
